{"code": "import json
import re

# Load children's books data
childrens_books_path = locals()['var_functions.query_db:10']
with open(childrens_books_path, 'r') as f:
    childrens_books = json.load(f)

# Load reviews from 2020 onwards
reviews_2020_path = locals()['var_functions.query_db:14']
with open(reviews_2020_path, 'r') as f:
    reviews_2020 = json.load(f)

# Extract numeric ID from book_id (e.g., "bookid_4" -> "4")
for book in childrens_books:
    match = re.search(r'bookid_(\d+)', book['book_id'])
    if match:
        book['numeric_id'] = match.group(1)
    else:
        book['numeric_id'] = None

# Extract numeric ID from purchase_id (e.g., "purchaseid_4" -> "4")
for review in reviews_2020:
    match = re.search(r'purchaseid_(\d+)', review['purchase_id'])
    if match:
        review['numeric_id'] = match.group(1)
    else:
        review['numeric_id'] = None

# Convert ratings to float
for review in reviews_2020:
    try:
        review['rating'] = float(review['rating'])
    except (ValueError, TypeError):
        review['rating'] = None

# Create a dictionary of children's books by numeric_id for easy lookup
childrens_books_dict = {book['numeric_id']: book for book in childrens_books if book['numeric_id']}

# Group reviews by numeric_id and calculate average rating
from collections import defaultdict
book_reviews = defaultdict(list)

for review in reviews_2020:
    numeric_id = review.get('numeric_id')
    if numeric_id and numeric_id in childrens_books_dict and review['rating'] is not None:
        book_reviews[numeric_id].append(review['rating'])

# Calculate average rating for each book and filter >= 4.5
result = []
for numeric_id, ratings in book_reviews.items():
    if ratings:
        avg_rating = sum(ratings) / len(ratings)
        if avg_rating >= 4.5:
            book = childrens_books_dict[numeric_id]
            result.append({
                'title': book['title'],
                'book_id': book['book_id'],
                'average_rating': round(avg_rating, 2),
                'review_count': len(ratings),
                'categories': book['categories']
            })

# Sort by average rating descending
result.sort(key=lambda x: x['average_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps(result, indent=2))"}

